module up_down_counter(reset, RST, EN, UP_DOWN, COUNT);
input reset, RST, EN, UP_DOWN;
output [2:0] COUNT;
reg [2:0] COUNT;

always @(posedge reset) begin
    if (RST)
        COUNT <= 3'b000;
    else if (EN) begin
        if (UP_DOWN)
            COUNT <= COUNT + 1;
        else
            COUNT <= COUNT - 1;
    end
end

endmodule
